import React from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { LogOut, Terminal as TerminalIcon, Cpu } from 'lucide-react';

const Navbar = () => {
  const { user, logout } = useAuth();
  const navigate = useNavigate();

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  return (
    <nav className="border-b border-white/5 bg-[#0a0a0a]/80 backdrop-blur-md sticky top-0 z-50">
      <div className="container mx-auto px-6 py-4 flex justify-between items-center">
        <Link to="/" className="flex items-center gap-2 group">
          <Cpu className="text-emerald-500 group-hover:rotate-90 transition-transform" size={20} />
          <span className="font-bold tracking-[0.2em] text-white uppercase text-sm">Finify_AI</span>
        </Link>

        {user && (
          <div className="flex items-center gap-8">
            <Link to="/dashboard" className="text-[10px] uppercase tracking-widest text-white/40 hover:text-emerald-500 transition-colors">Dashboard</Link>
            <Link to="/generate" className="text-[10px] uppercase tracking-widest text-white/40 hover:text-emerald-500 transition-colors">Strategy_Engine</Link>
            <div className="h-4 w-[1px] bg-white/10" />
            <div className="flex items-center gap-4">
              <span className="text-[9px] text-emerald-500 font-mono">Node_ID: {user.email}</span>
              <button onClick={handleLogout} className="emerald-btn py-2 px-4">
                <LogOut size={12} /> Exit_Terminal
              </button>
            </div>
          </div>
        )}
      </div>
    </nav>
  );
};

export default Navbar;
